<template><section class="page"><header><div><h2>{{t('promptops.evaluations.history')}}</h2><p>{{t('promptops.evaluations.historyDescription')}}</p></div></header><div class="filters"><input v-model="search" :placeholder="t('promptops.evaluations.search')"><select v-model="status"><option value="">{{t('promptops.evaluations.allStatuses')}}</option><option v-for="item in statuses" :key="item" :value="item">{{t(`promptops.evaluations.status.${item}`)}}</option></select></div><p v-if="loading">{{t('promptops.common.loading')}}</p><p v-else-if="error" class="error">{{error}}</p><p v-else-if="!filtered.length" class="empty">{{t('promptops.evaluations.empty')}}</p><table v-else><thead><tr><th>{{t('promptops.evaluations.run')}}</th><th>{{t('promptops.evaluations.dataset')}}</th><th>{{t('promptops.evaluations.prompt')}}</th><th>{{t('promptops.evaluations.model')}}</th><th>{{t('promptops.evaluations.progress')}}</th><th>{{t('promptops.evaluations.invocationSuccessRate')}}</th><th>{{t('promptops.evaluations.validationPassRate')}}</th><th>{{t('promptops.datasets.created')}}</th><th></th></tr></thead><tbody><tr v-for="run in paged" :key="run.id"><td><RouterLink :to="`/evaluations/${run.id}`">{{run.id.slice(0,8)}}</RouterLink><EvaluationStatusBadge :status="run.status"/></td><td>{{run.configSnapshot.dataset.name}}</td><td>{{run.configSnapshot.prompt.name}} · {{run.configSnapshot.promptVersion.versionNumber}}</td><td>{{run.providerId}} / {{run.modelId}}</td><td>{{run.progressPercent??0}}%</td><td>{{rate(run.metrics?.invocationSuccessRate)}}</td><td>{{rate(run.metrics?.validationPassRate)}}</td><td>{{date(run.createdAt)}}</td><td><button @click="retry(run.id)">{{t('promptops.evaluations.retryEntire')}}</button><button @click="remove(run.id)">{{t('promptops.evaluations.delete')}}</button></td></tr></tbody></table><footer><button :disabled="page===1" @click="page--">‹</button><span>{{page}}</span><button :disabled="page*10>=filtered.length" @click="page++">›</button></footer></section></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{RouterLink,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import{EVALUATION_RUN_STATUSES,type EvaluationRun}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import EvaluationStatusBadge from'../../components/promptops/evaluations/EvaluationStatusBadge.vue';const{t}=useI18n(),services=usePromptOpsServices(),router=useRouter(),runs=ref<EvaluationRun[]>([]),loading=ref(true),error=ref(''),search=ref(''),status=ref(''),page=ref(1),statuses=EVALUATION_RUN_STATUSES;const load=async()=>{loading.value=true;try{runs.value=(await services.evaluationQueryService.list({limit:500})).items}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{loading.value=false}};onMounted(load);const filtered=computed(()=>runs.value.filter(run=>(!status.value||run.status===status.value)&&(!search.value||`${run.id} ${run.configSnapshot.dataset.name} ${run.configSnapshot.prompt.name} ${run.providerId} ${run.modelId}`.toLowerCase().includes(search.value.toLowerCase())))),paged=computed(()=>filtered.value.slice((page.value-1)*10,page.value*10));const rate=(value?:number)=>value===undefined?'—':`${value.toFixed(1)}%`,date=(value:string)=>new Date(value).toLocaleString();const retry=async(id:string)=>{const run=await services.batchEvaluationService.retry(id,'entire');await router.push(`/evaluations/${run.id}`)};const remove=async(id:string)=>{if(!confirm(String(t('promptops.evaluations.deleteConfirm'))))return;await services.evaluationQueryService.deleteRun(id);await load()}</script>
<style scoped>.page{display:grid;gap:16px}.filters,footer{display:flex;gap:10px}.filters input{flex:1}input,select,button{padding:8px;border:1px solid #cbd5e1;border-radius:6px}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:10px;border-bottom:1px solid #e2e8f0}td:first-child{display:grid;gap:5px}.error{color:#b91c1c}.empty{text-align:center;padding:50px}footer{justify-content:center}</style>
